                                </div>
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium leading-none">
                                    Filter by Document File Date
                                </label>
                                <div className="relative">
                                    <Input
                                        type="date"
                                        value={date}
                                        onChange={handleDateChange}
                                    />
                                </div>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
